1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 1.1;
5	
6	const MAIN_ITEM_BASE_PREMIUM_BY_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
14	const COMPONENT_BASE_PREMIUM = 25;
15	const COMPONENT_BLOCK_PREMIUM = 60;
16	
17	export type Customer = {
18	  yearsInsured: number;
19	  previousQuotes: number;
20	};
21	
22	export type Item = {
23	  type: string;
24	};
25	
26	export type QuoteInput = {
27	  items: Item[];
28	  customer: Customer;
29	};
30	
31	const BLOCK_SIZE = 3;
32	
33	const formsOneBlock = (count: number): boolean => {
34	  if (count < BLOCK_SIZE) return false;
35	  const leftover = count - BLOCK_SIZE;
36	  return leftover !== 1;
37	};
38	
39	const componentGroupBase = (count: number): number => {
40	  const blocks = formsOneBlock(count) ? 1 : 0;
41	  const singles = count - blocks * BLOCK_SIZE;
42	  return blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_BASE_PREMIUM;
43	};
44	
45	const basePremium = (items: Item[]): number => {
46	  const componentCounts: Record<string, number> = {};
47	  let mainTotal = 0;
48	  for (const item of items) {
49	    if (COMPONENT_TYPES.has(item.type)) {
50	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
51	    } else {
52	      mainTotal += MAIN_ITEM_BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
53	    }
54	  }
55	  const componentTotal = Object.values(componentCounts).reduce(
56	    (sum, count) => sum + componentGroupBase(count),
57	    0
58	  );
59	  return mainTotal + componentTotal;
60	};
61	
62	const roundUpToGold = (amount: number): number => {
63	  const precisionSafe = Math.round(amount * 100) / 100;
64	  return Math.ceil(precisionSafe);
65	};
66	
67	export const quote = (input: QuoteInput): number => {
68	  const base = basePremium(input.items);
69	  const withSurchargeAndFee = base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
70	  return roundUpToGold(withSurchargeAndFee);
71	};
